import sqlite3, hmac
from hashlib import pbkdf2_hmac
def login(db, username, password):
    row = db.execute('SELECT pw_salt, pw_hash FROM users WHERE username = ?',
                     (username,)).fetchone()
    if row is None:
        return False
    salt, expected = row
    got = pbkdf2_hmac('sha256', password.encode(), salt, 200_000)
    return hmac.compare_digest(got, expected)

from urllib.parse import urlparse
import requests
ALLOWED_HOSTS = {'api.example.com', 'data.example.com'}
def fetch(url):
    parts = urlparse(url)
    if parts.scheme not in ('http', 'https'):
        raise ValueError('scheme')
    if parts.hostname not in ALLOWED_HOSTS:
        raise ValueError('host not allowed')
    return requests.get(url, timeout=5, allow_redirects=False).text

def search(db, term):
    return db.execute(
        'SELECT id, name FROM products WHERE name LIKE ? LIMIT 100',
        ('%' + term + '%',)).fetchall()

import json, hmac, hashlib, base64
def load_session(cookie, secret):
    body, sig = cookie.rsplit('.', 1)
    expected = hmac.new(secret, body.encode(), hashlib.sha256).hexdigest()
    if not hmac.compare_digest(expected, sig):
        raise ValueError('bad sig')
    return json.loads(base64.urlsafe_b64decode(body))
